function fieldsToContent(fields) {
  const actionsRaw = fields.actions;
  const normalizedActions = (() => {
    if (Array.isArray(actionsRaw)) {
      return actionsRaw.map((a) => String(a).trim()).filter((a) => a.length > 0);
    }
    if (typeof actionsRaw === "string") {
      return actionsRaw.split(",").map((a) => String(a).trim()).filter((a) => a.length > 0);
    }
    return [];
  })();
  const finalActions = normalizedActions.length > 0 ? normalizedActions : ["IGNORE"];
  const providers = Array.isArray(fields.providers) ? fields.providers.filter((p) => typeof p === "string") : typeof fields.providers === "string" ? fields.providers.split(",").map((p) => String(p).trim()).filter((p) => p.length > 0) : [];
  return {
    thought: String(fields.thought ?? ""),
    actions: finalActions,
    text: String(fields.text ?? ""),
    simple: fields.simple === true || fields.simple === "true",
    providers
  };
}
async function runAutonomyPostResponse(runtime2, autonomousMessage, fields, callback) {
  const responseContent = fieldsToContent(fields);
  if (autonomousMessage.id) {
    responseContent.inReplyTo = createUniqueUuid(runtime2, autonomousMessage.id);
  }
  const responseId = stringToUuid(v4_default());
  const responseMessages = [
    {
      id: responseId,
      entityId: runtime2.agentId,
      agentId: runtime2.agentId,
      content: responseContent,
      roomId: autonomousMessage.roomId,
      createdAt: Date.now()
    }
  ];
  const state2 = await runtime2.composeState(autonomousMessage, [
    "ACTIONS",
    "RECENT_MESSAGES",
    "EVALUATORS"
  ]);
  for (const responseMemory of responseMessages) {
    runtime2.logger.debug({ src: "autonomy:facade", memoryId: responseMemory.id }, "Saving autonomy response to memory");
    await runtime2.createMemory(responseMemory, "messages");
  }
  const isSimple = responseContent.actions?.length === 1 && String(responseContent.actions[0]).toUpperCase() === "REPLY" && (!responseContent.providers || responseContent.providers.length === 0);
  const mode = isSimple && responseContent.text ? "simple" : "actions";
  if (mode === "simple" && callback) {
    if (responseContent.text) {
      responseContent.text = runtime2.redactSecrets(responseContent.text);
    }
    await callback(responseContent);
  } else if (mode === "actions") {
    await runtime2.processActions(autonomousMessage, responseMessages, state2, async (content) => {
      runtime2.logger.debug({ src: "autonomy:facade", content }, "Autonomy action callback");
      if (callback) {
        return callback(content);
      }
      return [];
    }, {});
  }
  const didRespond = typeof responseContent.text === "string" && responseContent.text.trim().length > 0 || responseContent.actions && responseContent.actions.length > 0 && responseContent.actions[0]?.toUpperCase() !== "IGNORE";
  await runtime2.evaluate(autonomousMessage, state2, didRespond, async (content) => {
    runtime2.logger.debug({ src: "autonomy:facade", content }, "Autonomy evaluate callback");
    if (callback && content.text) {
      content.text = runtime2.redactSecrets(content.text);
      return callback(content);
    }
    return [];
  }, responseMessages);
}

