var sendToAdminAction = {
  name: "SEND_TO_ADMIN",
  description: "Send a message directly to the admin user from autonomous context",
  examples: [
    [
      {
        name: "Agent",
        content: {
          text: "I need to update the admin about my progress on the task.",
          action: "SEND_TO_ADMIN"
        }
      },
      {
        name: "Agent",
        content: {
          text: "Message sent to admin successfully."
        }
      }
    ],
    [
      {
        name: "Agent",
        content: {
          text: "I should let the admin know I completed the analysis.",
          action: "SEND_TO_ADMIN"
        }
      },
      {
        name: "Agent",
        content: {
          text: "Admin has been notified of the analysis completion."
        }
      }
    ]
  ],
  validate: async (runtime2, message2) => {
    const autonomyService = runtime2.getService(AUTONOMY_SERVICE_TYPE);
    if (!autonomyService) {
      return false;
    }
    const autonomousRoomId = autonomyService.getAutonomousRoomId?.();
    if (!autonomousRoomId || message2.roomId !== autonomousRoomId) {
      return false;
    }
    const adminUserId = runtime2.getSetting("ADMIN_USER_ID");
    if (typeof adminUserId !== "string" || adminUserId.length === 0) {
      return false;
    }
    const text = message2.content.text?.toLowerCase() || "";
    if (text.length === 0) {
      return false;
    }
    return ADMIN_KEYWORDS.some((keyword) => text.includes(keyword));
  },
  handler: async (runtime2, message2, _state2, _options, callback) => {
    const autonomyService = runtime2.getService(AUTONOMY_SERVICE_TYPE);
    if (!autonomyService) {
      return {
        success: false,
        text: "Autonomy service not available",
        data: { error: "Service unavailable" }
      };
    }
    const autonomousRoomId = autonomyService.getAutonomousRoomId?.();
    if (!autonomousRoomId || message2.roomId !== autonomousRoomId) {
      return {
        success: false,
        text: "Send to admin only available in autonomous context",
        data: { error: "Invalid context" }
      };
    }
    const adminUserId = runtime2.getSetting("ADMIN_USER_ID");
    if (typeof adminUserId !== "string" || adminUserId.length === 0) {
      return {
        success: false,
        text: "No admin user configured. Set ADMIN_USER_ID in settings.",
        data: { error: "No admin configured" }
      };
    }
    const adminMessages = await runtime2.getMemories({
      roomId: runtime2.agentId,
      count: 10,
      tableName: "memories"
    });
    let targetRoomId;
    if (adminMessages && adminMessages.length > 0) {
      const lastMessage = adminMessages[adminMessages.length - 1];
      targetRoomId = lastMessage.roomId ?? runtime2.agentId;
    } else {
      targetRoomId = runtime2.agentId;
    }
    const autonomousThought = message2.content.text || "";
    let messageToAdmin;
    if (autonomousThought.includes("completed") || autonomousThought.includes("finished")) {
      messageToAdmin = `I've completed a task and wanted to update you. My thoughts: ${autonomousThought}`;
    } else if (autonomousThought.includes("problem") || autonomousThought.includes("issue") || autonomousThought.includes("error")) {
      messageToAdmin = `I encountered something that might need your attention: ${autonomousThought}`;
    } else if (autonomousThought.includes("question") || autonomousThought.includes("unsure")) {
      messageToAdmin = `I have a question and would appreciate your guidance: ${autonomousThought}`;
    } else {
      messageToAdmin = `Autonomous update: ${autonomousThought}`;
    }
    const now = Date.now();
    const adminMessage = {
      id: stringToUuid(v4_default()),
      entityId: runtime2.agentId,
      roomId: targetRoomId,
      content: {
        text: messageToAdmin,
        source: "autonomy-to-admin",
        metadata: {
          type: "autonomous-to-admin-message",
          originalThought: autonomousThought,
          timestamp: now
        }
      },
      createdAt: now
    };
    await runtime2.createMemory(adminMessage, "memories");
    const successMessage = `Message sent to admin in room ${targetRoomId.slice(0, 8)}...`;
    if (callback) {
      await callback({
        text: successMessage,
        data: {
          adminUserId,
          targetRoomId,
          messageContent: messageToAdmin
        }
      });
    }
    return {
      success: true,
      text: successMessage,
      data: {
        adminUserId,
        targetRoomId,
        messageContent: messageToAdmin,
        sent: true
      }
    };
  }
};
