// src/utils/slice-to-fit-budget.ts
function sliceToFitBudget(items, estimateChars, targetChars, options) {
  if (items.length === 0)
    return [];
  if (targetChars <= 0)
    return [];
  const fromEnd = options?.fromEnd ?? false;
  let total = 0;
  let count = 0;
  const sizes = items.map(estimateChars);
  if (fromEnd) {
    for (let index = items.length - 1;index >= 0; index--) {
      if (total + sizes[index] > targetChars)
        break;
      total += sizes[index];
      count++;
    }
    const take = count > 0 ? count : 0;
    return items.slice(items.length - take);
  }
  for (;count < items.length; count++) {
    if (total + sizes[count] > targetChars)
      break;
    total += sizes[count];
  }
  return items.slice(0, count);
}

