class FollowUpService extends Service {
  static serviceType = "follow_up";
  capabilityDescription = "Task-based follow-up scheduling and management for contacts";
  rolodexService;
  constructor(runtime2) {
    super();
    if (runtime2) {
      this.runtime = runtime2;
      this.runtime.getServiceLoadPromise("rolodex").then((service3) => {
        this.rolodexService = service3;
        logger.info("[FollowUpService] Successfully acquired RolodexService via service promise");
      }).catch((error) => {
        logger.error("[FollowUpService] Failed to acquire RolodexService:", error instanceof Error ? error.message : String(error));
        throw new Error("[FollowUpService] RolodexService is not available");
      });
    }
  }
  async initialize(runtime2) {
    this.runtime = runtime2;
    if (!this.rolodexService) {
      this.rolodexService = await this.runtime.getServiceLoadPromise("rolodex");
      logger.info("[FollowUpService] Successfully acquired RolodexService via service promise");
    }
    this.registerFollowUpWorker();
    logger.info("[FollowUpService] Initialized successfully");
  }
  async stop() {
    logger.info("[FollowUpService] Stopped successfully");
  }
  static async start(runtime2) {
    const service3 = new FollowUpService(runtime2);
    await service3.initialize(runtime2);
    return service3;
  }
  async scheduleFollowUp(entityId, scheduledAt, reason, priority = "medium", message2) {
    const contact = await this.rolodexService.getContact(entityId);
    if (!contact) {
      throw new Error(`Contact ${entityId} not found`);
    }
    const task2 = {
      id: createUniqueUuid(this.runtime, `followup-${entityId}-${Date.now()}`),
      name: "follow_up",
      description: `Follow-up with contact: ${reason}`,
      entityId: this.runtime.agentId,
      roomId: stringToUuid(`rolodex-${this.runtime.agentId}`),
      worldId: stringToUuid(`rolodex-world-${this.runtime.agentId}`),
      tags: ["follow-up", priority, "rolodex", "queue"],
      dueAt: scheduledAt.getTime(),
      metadata: {
        targetEntityId: entityId,
        reason,
        priority,
        message: message2,
        scheduledAt: scheduledAt.toISOString(),
        status: "pending",
        createdAt: new Date().toISOString()
      }
    };
    await this.runtime.createTask(task2);
    await this.rolodexService.updateContact(entityId, {
      customFields: {
        ...contact.customFields,
        nextFollowUpAt: scheduledAt.toISOString(),
        nextFollowUpReason: reason
      }
    });
    logger.info(`[FollowUpService] Scheduled follow-up for ${entityId} at ${scheduledAt.toISOString()}`);
    return task2;
  }
  async getUpcomingFollowUps(days = 7, includeOverdue = true) {
    const now = Date.now();
    const futureDate = now + days * 24 * 60 * 60 * 1000;
    const tasks = await this.runtime.getTasks({
      entityId: this.runtime.agentId,
      tags: ["follow-up"],
      agentIds: [this.runtime.agentId]
    });
    const upcomingFollowUps = [];
    for (const task2 of tasks) {
      if (task2.metadata?.status !== "pending")
        continue;
      const scheduledAt = task2.metadata?.scheduledAt ? new Date(task2.metadata.scheduledAt).getTime() : 0;
      if (includeOverdue && scheduledAt < now) {} else if (scheduledAt >= now && scheduledAt <= futureDate) {} else {
        continue;
      }
      const targetEntityId = task2.metadata?.targetEntityId;
      if (targetEntityId) {
        const contact = await this.rolodexService.getContact(targetEntityId);
        if (contact) {
          upcomingFollowUps.push({ task: task2, contact });
        }
      }
    }
    upcomingFollowUps.sort((a, b) => {
      const aScheduled = a.task.metadata?.scheduledAt ? new Date(a.task.metadata.scheduledAt).getTime() : 0;
      const bScheduled = b.task.metadata?.scheduledAt ? new Date(b.task.metadata.scheduledAt).getTime() : 0;
      return aScheduled - bScheduled;
    });
    return upcomingFollowUps;
  }
  async completeFollowUp(taskId, notes) {
    try {
      const task2 = await this.runtime.getTask(taskId);
      if (!task2) {
        throw new Error(`Task ${taskId} not found`);
      }
      await this.runtime.updateTask(taskId, {
        metadata: {
          ...task2.metadata,
          status: "completed",
          completedAt: new Date().toISOString(),
          completionNotes: notes
        }
      });
      const targetEntityId = task2.metadata?.targetEntityId;
      if (targetEntityId) {
        const contact = await this.rolodexService.getContact(targetEntityId);
        if (contact) {
          const customFields = { ...contact.customFields };
          delete customFields.nextFollowUpAt;
          delete customFields.nextFollowUpReason;
          await this.rolodexService.updateContact(targetEntityId, {
            customFields
          });
        }
      }
    } catch (error) {
      logger.error("[FollowUpService] Error completing follow-up:", error instanceof Error ? error.message : String(error));
      throw error;
    }
    logger.info(`[FollowUpService] Completed follow-up task ${taskId}`);
  }
  async snoozeFollowUp(taskId, newDate) {
    try {
      const task2 = await this.runtime.getTask(taskId);
      if (!task2) {
        throw new Error(`Task ${taskId} not found`);
      }
      await this.runtime.updateTask(taskId, {
        metadata: {
          ...task2.metadata,
          scheduledAt: newDate.toISOString(),
          snoozedAt: new Date().toISOString(),
          originalScheduledAt: task2.metadata?.scheduledAt || task2.metadata?.createdAt
        }
      });
      const targetEntityId = task2.metadata?.targetEntityId;
      if (targetEntityId) {
        const contact = await this.rolodexService.getContact(targetEntityId);
        if (contact) {
          await this.rolodexService.updateContact(targetEntityId, {
            customFields: {
              ...contact.customFields,
              nextFollowUpAt: newDate.toISOString()
            }
          });
        }
      }
      logger.info(`[FollowUpService] Snoozed follow-up ${taskId} to ${newDate.toISOString()}`);
    } catch (error) {
      logger.error("[FollowUpService] Error snoozing follow-up:", error instanceof Error ? error.message : String(error));
      throw error;
    }
  }
  async getFollowUpSuggestions() {
    const contacts = await this.rolodexService.searchContacts({});
    const insights = await this.rolodexService.getRelationshipInsights(this.runtime.agentId);
    const needsAttentionById = new Map(insights.needsAttention.map((item) => [item.entity.id, item]));
    const candidates = contacts.filter((contact) => {
      const needsAttention = needsAttentionById.get(contact.entityId);
      return Boolean(needsAttention && needsAttention.daysSinceContact > 14);
    });
    const suggestionResults = await Promise.all(candidates.map(async (contact) => {
      const entity = await this.runtime.getEntityById(contact.entityId);
      if (!entity)
        return null;
      const needsAttention = needsAttentionById.get(contact.entityId);
      if (!needsAttention)
        return null;
      const analytics = await this.rolodexService.analyzeRelationship(this.runtime.agentId, contact.entityId);
      if (!analytics) {
        return null;
      }
      return {
        entityId: contact.entityId,
        entityName: entity.names[0] || "Unknown",
        reason: this.generateFollowUpReason(contact.categories, needsAttention.daysSinceContact, analytics.strength),
        daysSinceLastContact: needsAttention.daysSinceContact,
        relationshipStrength: analytics.strength,
        suggestedMessage: this.generateFollowUpMessage(entity.names[0], contact.categories, needsAttention.daysSinceContact)
      };
    }));
    const suggestions = suggestionResults.filter((suggestion) => suggestion !== null);
    suggestions.sort((a, b) => {
      const scoreA = a.relationshipStrength / 100 * a.daysSinceLastContact;
      const scoreB = b.relationshipStrength / 100 * b.daysSinceLastContact;
      return scoreB - scoreA;
    });
    return suggestions.slice(0, 10);
  }
  registerFollowUpWorker() {
    const worker = {
      name: "follow_up",
      shouldRun: async (runtime2, task2) => {
        const targetEntityId = task2.metadata?.targetEntityId;
        if (!targetEntityId)
          return false;
        const entity = await runtime2.getEntityById(targetEntityId);
        return entity != null;
      },
      execute: async (runtime2, _options, task2) => {
        try {
          const targetEntityId = task2.metadata?.targetEntityId;
          const message2 = task2.metadata?.message || "Time for a follow-up!";
          const entity = await runtime2.getEntityById(targetEntityId);
          if (!entity) {
            logger.warn(`[FollowUpService] Entity ${targetEntityId} not found for follow-up`);
            return;
          }
          const memory2 = {
            id: createUniqueUuid(runtime2, `followup-memory-${Date.now()}`),
            entityId: runtime2.agentId,
            agentId: runtime2.agentId,
            roomId: stringToUuid(`rolodex-${runtime2.agentId}`),
            content: {
              text: `Follow-up reminder: ${entity.names[0]} - ${task2.metadata?.reason || "Check in"}. ${message2}`,
              type: "follow_up_reminder"
            },
            metadata: {
              type: MemoryType.CUSTOM,
              source: "rolodex",
              targetEntityId,
              taskId: task2.id ?? "",
              priority: task2.metadata?.priority ?? "medium"
            },
            createdAt: Date.now()
          };
          await runtime2.createMemory(memory2, "reminders");
          await runtime2.emitEvent("follow_up:due", {
            taskId: task2.id ?? "",
            taskName: task2.name ?? "",
            entityId: entity.id ?? "",
            message: message2 ?? ""
          });
          logger.info(`[FollowUpService] Executed follow-up for ${entity.names[0]}`);
        } catch (error) {
          logger.error("[FollowUpService] Error executing follow-up:", error instanceof Error ? error.message : String(error));
          throw error;
        }
        return;
      }
    };
    this.runtime.registerTaskWorker(worker);
  }
  generateFollowUpReason(categories, daysSince, relationshipStrength) {
    if (categories.includes("family") && daysSince > 30) {
      return "It's been over a month since you checked in with family";
    }
    if (categories.includes("friend") && relationshipStrength > 70) {
      return "Maintain this strong friendship with regular contact";
    }
    if (categories.includes("colleague") && daysSince > 60) {
      return "Professional relationships benefit from periodic check-ins";
    }
    if (categories.includes("vip")) {
      return "VIP contact - priority follow-up recommended";
    }
    return `No contact for ${daysSince} days`;
  }
  generateFollowUpMessage(name, categories, _daysSince) {
    if (categories.includes("family")) {
      return `Hey ${name}, thinking of you! How have you been?`;
    }
    if (categories.includes("friend")) {
      return `Hi ${name}! It's been a while - would love to catch up!`;
    }
    if (categories.includes("colleague")) {
      return `Hi ${name}, hope you're doing well. Any updates on your projects?`;
    }
    return `Hi ${name}, just wanted to check in and see how you're doing!`;
  }
  async scheduleMultipleFollowUps(followUps) {
    const tasks = [];
    for (const followUp of followUps) {
      const task2 = await this.scheduleFollowUp(followUp.entityId, followUp.scheduledAt, followUp.reason, followUp.priority || "medium", followUp.message);
      tasks.push(task2);
    }
    logger.info(`[FollowUpService] Scheduled ${tasks.length} follow-ups`);
    return tasks;
  }
}

// src/services/rolodex.ts
init_logger();
