function contactInfoToMetadata(contactInfo) {
  return {
    entityId: contactInfo.entityId,
    categories: contactInfo.categories,
    tags: contactInfo.tags,
    preferences: contactInfo.preferences,
    customFields: contactInfo.customFields,
    privacyLevel: contactInfo.privacyLevel,
    lastModified: contactInfo.lastModified
  };
}
function metadataToContactInfo(data2) {
  return {
    entityId: data2.entityId,
    categories: data2.categories,
    tags: data2.tags,
    preferences: data2.preferences,
    customFields: data2.customFields ?? {},
    privacyLevel: data2.privacyLevel,
    lastModified: data2.lastModified
  };
}
function calculateRelationshipStrength({
  interactionCount,
  lastInteractionAt,
  messageQuality = 5,
  relationshipType = "acquaintance"
}) {
  const interactionScore = Math.min(interactionCount * 2, 40);
  let recencyScore = 0;
  if (lastInteractionAt) {
    const daysSinceLastInteraction = (Date.now() - new Date(lastInteractionAt).getTime()) / (1000 * 60 * 60 * 24);
    if (daysSinceLastInteraction < 1)
      recencyScore = 30;
    else if (daysSinceLastInteraction < 7)
      recencyScore = 25;
    else if (daysSinceLastInteraction < 30)
      recencyScore = 20;
    else if (daysSinceLastInteraction < 90)
      recencyScore = 10;
    else
      recencyScore = 5;
  }
  const qualityScore = messageQuality / 10 * 20;
  const relationshipBonus = {
    family: 10,
    friend: 8,
    colleague: 6,
    acquaintance: 4,
    unknown: 0
  };
  const totalStrength = interactionScore + recencyScore + qualityScore + (relationshipBonus[relationshipType] ?? 0);
  return Math.max(0, Math.min(100, Math.round(totalStrength)));
}

class RolodexService extends Service {
  static serviceType = "rolodex";
  capabilityDescription = "Comprehensive contact and relationship management service";
  contactInfoCache = new Map;
  analyticsCache = new Map;
  categoriesCache = [];
  static CONTACT_CACHE_LIMIT = 2000;
  static ANALYTICS_CACHE_LIMIT = 2000;
  setCacheWithLimit(cache, key, value, limit) {
    if (cache.has(key)) {
      cache.delete(key);
    }
    cache.set(key, value);
    if (cache.size > limit) {
      const firstKey = cache.keys().next().value;
      if (firstKey !== undefined) {
        cache.delete(firstKey);
      }
    }
  }
  async initialize(runtime2) {
    this.runtime = runtime2;
    this.categoriesCache = [
      { id: "friend", name: "Friend", color: "#4CAF50" },
      { id: "family", name: "Family", color: "#2196F3" },
      { id: "colleague", name: "Colleague", color: "#FF9800" },
      { id: "acquaintance", name: "Acquaintance", color: "#9E9E9E" },
      { id: "vip", name: "VIP", color: "#9C27B0" },
      { id: "business", name: "Business", color: "#795548" }
    ];
    await this.loadContactInfoFromComponents();
    logger.info("[RolodexService] Initialized successfully");
  }
  async stop() {
    this.contactInfoCache.clear();
    this.analyticsCache.clear();
    this.categoriesCache = [];
    logger.info("[RolodexService] Stopped successfully");
  }
  static async start(runtime2) {
    const service3 = new RolodexService;
    await service3.initialize(runtime2);
    return service3;
  }
  async loadContactInfoFromComponents() {
    const rooms = await this.runtime.getRooms(stringToUuid(`world-${this.runtime.agentId}`));
    const entityIds = new Set;
    for (const room of rooms) {
      const entities = await this.runtime.getEntitiesForRoom(room.id, true);
      for (const entity of entities) {
        entityIds.add(entity.id);
      }
    }
    for (const entityId of entityIds) {
      const components2 = await this.runtime.getComponents(entityId);
      const contactComponent = components2.find((c) => c.type === "contact_info" && c.agentId === this.runtime.agentId);
      if (contactComponent?.data) {
        const contactInfo = metadataToContactInfo(contactComponent.data);
        this.setCacheWithLimit(this.contactInfoCache, entityId, contactInfo, RolodexService.CONTACT_CACHE_LIMIT);
      }
    }
    logger.info(`[RolodexService] Loaded ${this.contactInfoCache.size} contacts from components`);
  }
  async addContact(entityId, categories = ["acquaintance"], preferences, customFields) {
    const contactInfo = {
      entityId,
      categories,
      tags: [],
      preferences: preferences ?? {},
      customFields: customFields ?? {},
      privacyLevel: "private",
      lastModified: new Date().toISOString()
    };
    await this.runtime.createComponent({
      id: stringToUuid(`contact-${entityId}-${this.runtime.agentId}`),
      type: "contact_info",
      agentId: this.runtime.agentId,
      entityId,
      roomId: stringToUuid(`rolodex-${this.runtime.agentId}`),
      worldId: stringToUuid(`rolodex-world-${this.runtime.agentId}`),
      sourceEntityId: this.runtime.agentId,
      data: contactInfoToMetadata(contactInfo),
      createdAt: Date.now()
    });
    this.setCacheWithLimit(this.contactInfoCache, entityId, contactInfo, RolodexService.CONTACT_CACHE_LIMIT);
    const entity = await this.runtime.getEntityById(entityId);
    if (entity) {
      await this.runtime.emitEvent("entity:updated" /* UPDATED */, {
        entityId: entity.id ?? "",
        source: "rolodex"
      });
    }
    logger.info(`[RolodexService] Added contact ${entityId} with categories: ${categories.join(", ")}`);
    return contactInfo;
  }
  async updateContact(entityId, updates) {
    const existing = await this.getContact(entityId);
    if (!existing) {
      logger.warn(`[RolodexService] Contact ${entityId} not found`);
      return null;
    }
    const updated = {
      ...existing,
      ...updates,
      entityId,
      lastModified: new Date().toISOString()
    };
    const components2 = await this.runtime.getComponents(entityId);
    const contactComponent = components2.find((c) => c.type === "contact_info" && c.agentId === this.runtime.agentId);
    if (contactComponent) {
      await this.runtime.updateComponent({
        ...contactComponent,
        data: contactInfoToMetadata(updated)
      });
    }
    this.setCacheWithLimit(this.contactInfoCache, entityId, updated, RolodexService.CONTACT_CACHE_LIMIT);
    logger.info(`[RolodexService] Updated contact ${entityId}`);
    return updated;
  }
  async getContact(entityId) {
    if (this.contactInfoCache.has(entityId)) {
      const cached = this.contactInfoCache.get(entityId);
      if (cached) {
        return cached;
      }
    }
    const components2 = await this.runtime.getComponents(entityId);
    const contactComponent = components2.find((c) => c.type === "contact_info" && c.agentId === this.runtime.agentId);
    if (contactComponent?.data) {
      const contactInfo = metadataToContactInfo(contactComponent.data);
      this.setCacheWithLimit(this.contactInfoCache, entityId, contactInfo, RolodexService.CONTACT_CACHE_LIMIT);
      return contactInfo;
    }
    return null;
  }
  async removeContact(entityId) {
    const existing = await this.getContact(entityId);
    if (!existing) {
      logger.warn(`[RolodexService] Contact ${entityId} not found`);
      return false;
    }
    const components2 = await this.runtime.getComponents(entityId);
    const contactComponent = components2.find((c) => c.type === "contact_info" && c.agentId === this.runtime.agentId);
    if (contactComponent) {
      await this.runtime.deleteComponent(contactComponent.id);
    }
    this.contactInfoCache.delete(entityId);
    logger.info(`[RolodexService] Removed contact ${entityId}`);
    return true;
  }
  async searchContacts(criteria) {
    const results = [];
    for (const [, contactInfo] of this.contactInfoCache) {
      let matches = true;
      if (criteria.categories && criteria.categories.length > 0) {
        const categorySet = new Set(contactInfo.categories);
        matches = matches && criteria.categories.some((cat) => categorySet.has(cat));
      }
      if (criteria.tags && criteria.tags.length > 0) {
        const tagSet = new Set(contactInfo.tags);
        matches = matches && criteria.tags.some((tag) => tagSet.has(tag));
      }
      if (criteria.privacyLevel) {
        matches = matches && contactInfo.privacyLevel === criteria.privacyLevel;
      }
      if (matches) {
        results.push(contactInfo);
      }
    }
    if (criteria.searchTerm) {
      const searchTermLower = criteria.searchTerm.toLowerCase();
      const entities = await Promise.all(results.map((contact) => this.runtime.getEntityById(contact.entityId)));
      const filteredResults = [];
      for (let i = 0;i < results.length; i++) {
        const entity = entities[i];
        if (entity?.names.some((name) => name.toLowerCase().includes(searchTermLower))) {
          filteredResults.push(results[i]);
        }
      }
      return filteredResults;
    }
    return results;
  }
  async analyzeRelationship(sourceEntityId, targetEntityId) {
    const cacheKey = `${sourceEntityId}-${targetEntityId}`;
    if (this.analyticsCache.has(cacheKey)) {
      const cached = this.analyticsCache.get(cacheKey);
      if (cached) {
        if (cached.lastInteractionAt && Date.now() - new Date(cached.lastInteractionAt).getTime() < 3600000) {
          return cached;
        }
      }
    }
    const relationships = await this.runtime.getRelationships({
      entityIds: [sourceEntityId]
    });
    const relationship = relationships.find((r) => r.targetEntityId === targetEntityId || r.sourceEntityId === targetEntityId);
    if (!relationship) {
      return null;
    }
    const messages = await this.runtime.getMemories({
      tableName: "messages",
      entityId: sourceEntityId,
      count: 100
    });
    const interactions = messages.filter((m) => m.content.inReplyTo === targetEntityId || m.entityId === targetEntityId && m.content.inReplyTo === sourceEntityId);
    const interactionCount = interactions.length;
    const lastInteraction = interactions[0];
    const lastInteractionAt = lastInteraction?.createdAt ? new Date(lastInteraction.createdAt).toISOString() : undefined;
    let totalResponseTime = 0;
    let responseCount = 0;
    for (let i = 0;i < interactions.length - 1; i++) {
      const current = interactions[i];
      const next = interactions[i + 1];
      if (current.entityId !== next.entityId && current.createdAt && next.createdAt) {
        const timeDiff = new Date(next.createdAt).getTime() - new Date(current.createdAt).getTime();
        totalResponseTime += timeDiff;
        responseCount++;
      }
    }
    const averageResponseTime = responseCount > 0 ? totalResponseTime / responseCount : undefined;
    const topicsSet = new Set;
    for (const msg of interactions) {
      const text = msg.content.text || "";
      const keywords = text.match(/\b[A-Z][a-z]+\b/g) || [];
      for (const k of keywords) {
        topicsSet.add(k);
      }
    }
    const strength = calculateRelationshipStrength({
      interactionCount,
      lastInteractionAt,
      relationshipType: relationship.relationshipType
    });
    const analytics = {
      strength,
      interactionCount,
      lastInteractionAt,
      averageResponseTime,
      sentimentScore: 0.7,
      topicsDiscussed: Array.from(topicsSet).slice(0, 10)
    };
    if (relationship.strength !== strength || relationship.lastInteractionAt !== lastInteractionAt) {
      const relationshipComponent = {
        id: stringToUuid(`relationship-${relationship.id}`),
        type: "relationship_update",
        agentId: this.runtime.agentId,
        entityId: relationship.sourceEntityId,
        roomId: stringToUuid(`rolodex-${this.runtime.agentId}`),
        worldId: stringToUuid(`rolodex-world-${this.runtime.agentId}`),
        sourceEntityId: relationship.sourceEntityId,
        data: {
          targetEntityId: relationship.targetEntityId,
          strength,
          lastInteractionAt,
          metadata: relationship.metadata
        },
        createdAt: Date.now()
      };
      await this.runtime.createComponent(relationshipComponent);
    }
    this.setCacheWithLimit(this.analyticsCache, cacheKey, analytics, RolodexService.ANALYTICS_CACHE_LIMIT);
    return analytics;
  }
  async getRelationshipInsights(entityId) {
    const relationships = await this.runtime.getRelationships({
      entityIds: [entityId]
    });
    const insights = {
      strongestRelationships: [],
      needsAttention: [],
      recentInteractions: []
    };
    const targets = relationships.map((rel) => rel.sourceEntityId === entityId ? rel.targetEntityId : rel.sourceEntityId);
    const entities = await Promise.all(targets.map((target) => this.runtime.getEntityById(target)));
    const analyticsResults = await Promise.all(targets.map((target, index) => entities[index] ? this.analyzeRelationship(entityId, target) : null));
    for (let i = 0;i < relationships.length; i++) {
      const entity = entities[i];
      const analytics = analyticsResults[i];
      if (!entity || !analytics)
        continue;
      if (analytics.strength > 70) {
        insights.strongestRelationships.push({ entity, analytics });
      }
      if (analytics.lastInteractionAt) {
        const daysSince = (Date.now() - new Date(analytics.lastInteractionAt).getTime()) / (1000 * 60 * 60 * 24);
        if (daysSince > 30) {
          insights.needsAttention.push({
            entity,
            daysSinceContact: Math.round(daysSince)
          });
        }
        if (daysSince < 7) {
          insights.recentInteractions.push({
            entity,
            lastInteraction: analytics.lastInteractionAt
          });
        }
      }
    }
    insights.strongestRelationships.sort((a, b) => b.analytics.strength - a.analytics.strength);
    insights.needsAttention.sort((a, b) => b.daysSinceContact - a.daysSinceContact);
    insights.recentInteractions.sort((a, b) => new Date(b.lastInteraction).getTime() - new Date(a.lastInteraction).getTime());
    return insights;
  }
  async getCategories() {
    return this.categoriesCache;
  }
  async addCategory(category) {
    if (this.categoriesCache.find((c) => c.id === category.id)) {
      throw new Error(`Category ${category.id} already exists`);
    }
    this.categoriesCache.push(category);
    logger.info(`[RolodexService] Added category: ${category.name}`);
  }
  async setContactPrivacy(entityId, privacyLevel) {
    const contact = await this.getContact(entityId);
    if (!contact)
      return false;
    contact.privacyLevel = privacyLevel;
    await this.updateContact(entityId, { privacyLevel });
    logger.info(`[RolodexService] Set privacy level for ${entityId} to ${privacyLevel}`);
    return true;
  }
  async canAccessContact(requestingEntityId, targetEntityId) {
    const contact = await this.getContact(targetEntityId);
    if (!contact)
      return false;
    if (requestingEntityId === this.runtime.agentId)
      return true;
    switch (contact.privacyLevel) {
      case "public":
        return true;
      case "private":
        return requestingEntityId === targetEntityId;
      case "restricted":
        return false;
      default:
        return false;
    }
  }
}

