var spec22 = requireActionSpec("REMOVE_CONTACT");
var REMOVE_CONTACT_INTENT = /remove|delete|drop.*contact|remove.*from.*rolodex/i;
var removeContactAction = {
  name: spec22.name,
  similes: spec22.similes ? [...spec22.similes] : [],
  description: spec22.description,
  examples: spec22.examples ?? [],
  validate: async (runtime2, message2, _state2) => {
    const hasService = !!runtime2.getService("rolodex");
    const text = message2.content.text;
    if (!text)
      return false;
    const hasIntent = REMOVE_CONTACT_INTENT.test(text);
    return hasService && !!hasIntent;
  },
  handler: async (runtime2, message2, state2, _options, callback) => {
    try {
      const rolodexService = runtime2.getService("rolodex");
      if (!rolodexService) {
        throw new Error("RolodexService not available");
      }
      const removeState = {
        values: {
          ...state2?.values,
          message: message2.content.text,
          senderName: state2?.values?.senderName || "User",
          senderId: message2.entityId
        },
        data: state2?.data || {},
        text: state2?.text || ""
      };
      const prompt = composePromptFromState({
        state: removeState,
        template: removeContactTemplate
      });
      const response = await runtime2.useModel(ModelType.TEXT_SMALL, {
        prompt,
        stopSequences: []
      });
      const parsed = parseKeyValueXml(response);
      if (!parsed?.contactName) {
        logger.warn("[RemoveContact] No contact name provided");
        await callback?.({
          text: "I couldn't determine which contact to remove. Please specify the contact name."
        });
        return;
      }
      const confirmed = parsed.confirmed?.trim().toLowerCase();
      if (confirmed !== "yes") {
        await callback?.({
          text: `To remove ${parsed.contactName} from your contacts, please confirm by saying "yes, remove ${parsed.contactName}".`
        });
        return;
      }
      const contacts = await rolodexService.searchContacts({
        searchTerm: parsed.contactName
      });
      if (contacts.length === 0) {
        await callback?.({
          text: `I couldn't find a contact named "${parsed.contactName}" in the rolodex.`
        });
        return;
      }
      const contact = contacts[0];
      const removed = await rolodexService.removeContact(contact.entityId);
      if (removed) {
        const responseText = `I've removed ${parsed.contactName} from your contacts.`;
        await callback?.({
          text: responseText,
          actions: ["REMOVE_CONTACT"]
        });
        logger.info(`[RemoveContact] Removed contact ${contact.entityId}`);
        return {
          success: true,
          values: { contactId: contact.entityId },
          data: { success: true },
          text: responseText
        };
      } else {
        throw new Error("Failed to remove contact");
      }
    } catch (error) {
      logger.error("[RemoveContact] Error:", error instanceof Error ? error.message : String(error));
      await callback?.({
        text: "I encountered an error while removing the contact. Please try again.",
        error: error instanceof Error ? error.message : "Unknown error"
      });
    }
  }
};
// src/advanced-capabilities/actions/roles.ts
init_spec_helpers();
init_logger();
init_types5();
init_utils5();
var spec23 = requireActionSpec("UPDATE_ROLE");
var ROLE_OWNER = "OWNER";
var ROLE_ADMIN = "ADMIN";
var ROLE_NONE = "NONE";
var canModifyRole = (currentRole, targetRole, newRole) => {
  if (targetRole === currentRole) {
    return false;
  }
  switch (currentRole) {
    case ROLE_OWNER:
      return true;
    case ROLE_ADMIN:
      return newRole !== ROLE_OWNER;
    default:
      return false;
  }
};
var updateRoleAction = {
  name: spec23.name,
  similes: spec23.similes ? [...spec23.similes] : [],
  description: spec23.description,
  examples: spec23.examples ?? [],
  validate: async (runtime2, message2, state2) => {
    const channelType = message2.content.channelType;
    if (channelType !== ChannelType.GROUP && channelType !== ChannelType.WORLD) {
      return false;
    }
    const room = state2?.data?.room ?? await runtime2.getRoom(message2.roomId);
    if (!room || !room.messageServerId) {
      return false;
    }
    return true;
  },
  handler: async (runtime2, message2, state2, _options, callback) => {
    if (!state2) {
      logger.error({
        src: "plugin:advanced-capabilities:action:update_role",
        agentId: runtime2.agentId
      }, "State is required for role assignment");
      return {
        text: "State is required for role assignment",
        values: {
          success: false,
          error: "STATE_REQUIRED"
        },
        data: {
          actionName: "UPDATE_ROLE",
          error: "State is required"
        },
        success: false,
        error: new Error("State is required for role assignment")
      };
    }
    const { roomId } = message2;
    const worldId = runtime2.getSetting("WORLD_ID");
    let world = null;
    if (worldId) {
      world = await runtime2.getWorld(worldId);
    }
    if (!world) {
      logger.error({
        src: "plugin:advanced-capabilities:action:update_role",
        agentId: runtime2.agentId
      }, "World not found");
      await callback?.({
        text: "I couldn't find the world. This action only works in a world."
      });
      return {
        text: "World not found",
        values: {
          success: false,
          error: "WORLD_NOT_FOUND"
        },
        data: {
          actionName: "UPDATE_ROLE",
          error: "World not found"
        },
        success: false
      };
    }
    if (!world.metadata?.roles) {
      world.metadata = world.metadata || {};
      world.metadata.roles = {};
    }
    const entities = await runtime2.getEntitiesForRoom(roomId);
    const entityById = new Map;
    for (const entity of entities) {
      if (entity.id) {
        entityById.set(entity.id, entity);
      }
    }
    const requesterRole = world.metadata.roles[message2.entityId] || ROLE_NONE;
    const extractionPrompt = composePrompt({
      state: {
        ...state2.values,
        content: state2.text
      },
      template: `# Task: Parse Role Assignment

I need to extract user role assignments from the input text. Users can be referenced by name, username, or mention.

The available role types are:
- OWNER: Full control over the server and all settings
- ADMIN: Ability to manage channels and moderate content
- NONE: Regular user with no special permissions

# Current context:
{{content}}

Do NOT include any thinking, reasoning, or <think> sections in your response. 
Go directly to the XML response format without any preamble or explanation.

Format your response as XML with multiple assignments:
<response>
  <assignments>
    <assignment>
      <entityId>John</entityId>
      <newRole>ADMIN</newRole>
    </assignment>
    <assignment>
      <entityId>Sarah</entityId>
      <newRole>OWNER</newRole>
    </assignment>
  </assignments>
</response>

IMPORTANT: Your response must ONLY contain the <response></response> XML block above. Do not include any text, thinking, or reasoning before or after this XML block. Start your response immediately with <response> and end with </response>.`
    });
    const response = await runtime2.useModel(ModelType.TEXT_SMALL, {
      prompt: extractionPrompt,
      stopSequences: []
    });
    const parsedXml = parseKeyValueXml(response);
    let assignments = [];
    if (parsedXml?.assignments?.assignment) {
      const assignmentArray = Array.isArray(parsedXml.assignments.assignment) ? parsedXml.assignments.assignment : [parsedXml.assignments.assignment];
      assignments = assignmentArray.filter((a) => !!a.entityId).map((a) => ({
        entityId: a.entityId,
        newRole: a.newRole
      }));
    }
    if (!assignments.length) {
      await callback?.({
        text: "No valid role assignments found in the request.",
        actions: ["UPDATE_ROLE"],
        source: "discord"
      });
      return {
        text: "No valid role assignments found",
        values: {
          success: false,
          error: "NO_ASSIGNMENTS"
        },
        data: {
          actionName: "UPDATE_ROLE",
          error: "No valid role assignments found in the request"
        },
        success: false
      };
    }
    let worldUpdated = false;
    const successfulUpdates = [];
    const failedUpdates = [];
    for (const assignment of assignments) {
      const targetEntity = entityById.get(assignment.entityId);
      if (!targetEntity) {
        logger.error({
          src: "plugin:advanced-capabilities:action:update_role",
          agentId: runtime2.agentId,
          entityId: assignment.entityId
        }, "Could not find an ID to assign to");
        failedUpdates.push({
          entityId: assignment.entityId,
          reason: "Entity not found"
        });
        continue;
      }
      const entityIdAsUuid = assignment.entityId;
      const currentRole = world.metadata.roles[entityIdAsUuid] ?? null;
      if (!canModifyRole(requesterRole, currentRole, assignment.newRole)) {
        await callback?.({
          text: `You don't have permission to change ${targetEntity?.names[0]}'s role to ${assignment.newRole}.`,
          actions: ["UPDATE_ROLE"],
          source: "discord"
        });
        failedUpdates.push({
          entityId: assignment.entityId,
          reason: "Insufficient permissions"
        });
        continue;
      }
      world.metadata.roles[entityIdAsUuid] = assignment.newRole;
      worldUpdated = true;
      successfulUpdates.push({
        entityId: assignment.entityId,
        entityName: targetEntity?.names[0] || "Unknown",
        newRole: assignment.newRole
      });
      await callback?.({
        text: `Updated ${targetEntity?.names[0]}'s role to ${assignment.newRole}.`,
        actions: ["UPDATE_ROLE"],
        source: "discord"
      });
    }
    if (worldUpdated) {
      try {
        await runtime2.updateWorld(world);
        logger.info({
          src: "plugin:advanced-capabilities:action:update_role",
          agentId: runtime2.agentId,
          messageServerId: world.messageServerId
        }, "Updated roles in world metadata");
      } catch (error) {
        logger.error({
          src: "plugin:advanced-capabilities:action:update_role",
          agentId: runtime2.agentId,
          error: error instanceof Error ? error.message : String(error)
        }, "Failed to save world updates");
        return {
          text: "Failed to save role updates",
          values: {
            success: false,
            error: "SAVE_FAILED"
          },
          data: {
            actionName: "UPDATE_ROLE",
            error: error instanceof Error ? error.message : String(error),
            attemptedUpdates: successfulUpdates
          },
          success: false,
          error: error instanceof Error ? error : new Error(String(error))
        };
      }
    }
    return {
      text: `Role updates completed: ${successfulUpdates.length} successful, ${failedUpdates.length} failed`,
      values: {
        success: true,
        successfulUpdates: successfulUpdates.length,
        failedUpdates: failedUpdates.length
      },
      data: {
        actionName: "UPDATE_ROLE",
        successfulUpdateCount: successfulUpdates.length,
        failedUpdateCount: failedUpdates.length,
        worldId: world.id ?? "",
        messageServerId: world.messageServerId ?? ""
      },
      success: true
    };
  }
};
