var spec25 = requireActionSpec("SEARCH_CONTACTS");
var SEARCH_KEYWORDS = [
  "list",
  "show",
  "search",
  "find",
  "contacts",
  "friends",
  "colleagues",
  "vip",
  "who"
];
var searchContactsAction = {
  name: spec25.name,
  description: spec25.description,
  similes: spec25.similes ? [...spec25.similes] : [],
  examples: spec25.examples ?? [],
  validate: async (runtime2, message2, _state2) => {
    const rolodexService = runtime2.getService("rolodex");
    if (!rolodexService) {
      logger.warn("[SearchContacts] RolodexService not available");
      return false;
    }
    const messageText = message2.content.text?.toLowerCase() || "";
    if (!messageText)
      return false;
    return SEARCH_KEYWORDS.some((keyword) => messageText.includes(keyword));
  },
  handler: async (runtime2, message2, state2, _options, callback) => {
    const rolodexService = runtime2.getService("rolodex");
    if (!rolodexService) {
      throw new Error("RolodexService not available");
    }
    if (!state2) {
      state2 = {
        values: {},
        data: {},
        text: ""
      };
    }
    state2.values = {
      ...state2.values,
      message: message2.content.text,
      senderId: message2.entityId,
      senderName: state2.values?.senderName || "User"
    };
    const prompt = composePromptFromState({
      state: state2,
      template: searchContactsTemplate
    });
    const response = await runtime2.useModel(ModelType.TEXT_SMALL, {
      prompt,
      stopSequences: []
    });
    const parsedResponse = parseKeyValueXml(response);
    const criteria = {};
    if (parsedResponse?.categories) {
      criteria.categories = parsedResponse.categories.split(",").map((c) => c.trim()).filter(Boolean);
    }
    if (parsedResponse?.searchTerm) {
      criteria.searchTerm = parsedResponse.searchTerm;
    }
    if (parsedResponse?.tags) {
      criteria.tags = parsedResponse.tags.split(",").map((t) => t.trim()).filter(Boolean);
    }
    const contacts = await rolodexService.searchContacts(criteria);
    const contactDetails = await Promise.all(contacts.map(async (contact) => {
      const entity = await runtime2.getEntityById(contact.entityId);
      return {
        contact,
        entity,
        name: entity?.names[0] || "Unknown"
      };
    }));
    let responseText = "";
    if (contactDetails.length === 0) {
      responseText = "No contacts found matching your criteria.";
    } else if (parsedResponse?.intent === "count") {
      responseText = `I found ${contactDetails.length} contact${contactDetails.length !== 1 ? "s" : ""} matching your criteria.`;
    } else {
      if (!criteria.categories || criteria.categories.length === 0) {
        const grouped = {};
        for (const item of contactDetails) {
          for (const cat of item.contact.categories) {
            const bucket = grouped[cat];
            if (bucket) {
              bucket.push(item);
            } else {
              grouped[cat] = [item];
            }
          }
        }
        const lines = [];
        lines.push(`I found ${contactDetails.length} contact${contactDetails.length !== 1 ? "s" : ""}:`, "");
        for (const category in grouped) {
          const items = grouped[category];
          if (!items)
            continue;
          lines.push(`**${category.charAt(0).toUpperCase() + category.slice(1)}s:**`);
          for (const item of items) {
            let line = `- ${item.name}`;
            if (item.contact.tags.length > 0) {
              line += ` [${item.contact.tags.join(", ")}]`;
            }
            lines.push(line);
          }
          lines.push("");
        }
        responseText = lines.join(`
`).trim();
      } else {
        const categoryName = criteria.categories[0];
        const lines = [`Your ${categoryName}s:`];
        for (const item of contactDetails) {
          let line = `- ${item.name}`;
          if (item.contact.tags.length > 0) {
            line += ` [${item.contact.tags.join(", ")}]`;
          }
          lines.push(line);
        }
        responseText = lines.join(`
`);
      }
    }
    if (callback) {
      await callback({
        text: responseText,
        action: "SEARCH_CONTACTS",
        metadata: {
          count: contactDetails.length,
          criteria,
          success: true
        }
      });
    }
    return {
      success: true,
      values: {
        count: contactDetails.length,
        criteria
      },
      data: {
        count: contactDetails.length,
        criteria,
        contacts: contactDetails.map((d) => ({
          id: d.contact.entityId,
          name: d.name,
          categories: d.contact.categories,
          tags: d.contact.tags
        }))
      },
      text: responseText
    };
  }
};
