// src/advanced-capabilities/actions/updateContact.ts
init_spec_helpers();
init_logger();
init_types5();
init_utils5();
var spec30 = requireActionSpec("UPDATE_CONTACT");
var UPDATE_CONTACT_INTENT = /update|edit|modify|change|add.*to|remove.*from/i;
var parseKeyValueList = (value) => {
  if (!value)
    return {};
  const result = {};
  const entries = value.split(",");
  for (const entry of entries) {
    const [key, val] = entry.split(":").map((s) => s.trim());
    if (key && val) {
      result[key] = val;
    }
  }
  return result;
};
var updateContactAction = {
  name: spec30.name,
  similes: spec30.similes ? [...spec30.similes] : [],
  description: spec30.description,
  examples: spec30.examples ?? [],
  validate: async (runtime2, message2, _state2) => {
    const hasService = !!runtime2.getService("rolodex");
    const text = message2.content.text;
    if (!text)
      return false;
    const hasIntent = UPDATE_CONTACT_INTENT.test(text);
    return hasService && !!hasIntent;
  },
  handler: async (runtime2, message2, state2, _options, callback) => {
    try {
      const rolodexService = runtime2.getService("rolodex");
      if (!rolodexService) {
        throw new Error("RolodexService not available");
      }
      const updateState = {
        values: {
          ...state2?.values,
          message: message2.content.text,
          senderName: state2?.values?.senderName || "User",
          senderId: message2.entityId,
          currentDateTime: new Date().toISOString()
        },
        data: state2?.data || {},
        text: state2?.text || ""
      };
      const prompt = composePromptFromState({
        state: updateState,
        template: updateContactTemplate
      });
      const response = await runtime2.useModel(ModelType.TEXT_SMALL, {
        prompt
      });
      const parsed = parseKeyValueXml(response);
      if (!parsed) {
        logger.warn("[UpdateContact] Failed to parse response");
        await callback?.({
          text: "I couldn't understand the update request. Please try again."
        });
        return;
      }
      const contactName = parsed.contactName?.trim();
      if (!contactName) {
        logger.warn("[UpdateContact] No contact name provided");
        await callback?.({
          text: "I couldn't determine which contact to update. Please specify the contact name."
        });
        return;
      }
      const contacts = await rolodexService.searchContacts({
        searchTerm: contactName
      });
      if (contacts.length === 0) {
        await callback?.({
          text: `I couldn't find a contact named "${contactName}" in the rolodex.`
        });
        return;
      }
      const contact = contacts[0];
      const operation = parsed.operation || "replace";
      const updateData = {};
      if (parsed.categories) {
        const newCategories = parsed.categories.split(",").map((c) => c.trim()).filter(Boolean);
        if (operation === "add_to" && contact.categories) {
          updateData.categories = [
            ...new Set([...contact.categories, ...newCategories])
          ];
        } else {
          updateData.categories = newCategories;
        }
      }
      if (parsed.tags) {
        const newTags = parsed.tags.split(",").map((t) => t.trim()).filter(Boolean);
        if (operation === "add_to" && contact.tags) {
          updateData.tags = [...new Set([...contact.tags, ...newTags])];
        } else {
          updateData.tags = newTags;
        }
      }
      if (parsed.preferences) {
        const newPrefs = parseKeyValueList(parsed.preferences);
        if (operation === "add_to" && contact.preferences) {
          updateData.preferences = { ...contact.preferences, ...newPrefs };
        } else {
          updateData.preferences = newPrefs;
        }
      }
      if (parsed.customFields) {
        const newFields = parseKeyValueList(parsed.customFields);
        if (operation === "add_to" && contact.customFields) {
          updateData.customFields = { ...contact.customFields, ...newFields };
        } else {
          updateData.customFields = newFields;
        }
      }
      const updated = await rolodexService.updateContact(contact.entityId, updateData);
      if (updated) {
        const responseText = `I've updated ${contactName}'s contact information. ${updateData.categories ? `Categories: ${updateData.categories.join(", ")}. ` : ""}${updateData.tags ? `Tags: ${updateData.tags.join(", ")}. ` : ""}`;
        await callback?.({
          text: responseText,
          actions: ["UPDATE_CONTACT_INFO"]
        });
        logger.info(`[UpdateContact] Updated contact ${contact.entityId}`);
        return {
          success: true,
          values: {
            contactId: contact.entityId,
            categoriesStr: updateData.categories?.join(",") ?? "",
            tagsStr: updateData.tags?.join(",") ?? ""
          },
          data: {
            success: true,
            updatedFieldsStr: Object.keys(updateData).join(",")
          },
          text: responseText
        };
      } else {
        throw new Error("Failed to update contact");
      }
    } catch (error) {
      logger.error("[UpdateContact] Error:", error instanceof Error ? error.message : String(error));
      await callback?.({
        text: "I encountered an error while updating the contact. Please try again.",
        error: error instanceof Error ? error.message : "Unknown error"
      });
    }
  }
};
