async function analyzeRelationships(runtime2, messages, _rolodexService) {
  const messagesBySender = new Map;
  for (const msg of messages) {
    const senderMessages = messagesBySender.get(msg.entityId) || [];
    senderMessages.push(msg);
    messagesBySender.set(msg.entityId, senderMessages);
  }
  const senders = Array.from(messagesBySender.keys());
  for (let i = 0;i < senders.length; i++) {
    for (let j = i + 1;j < senders.length; j++) {
      const entityA = senders[i];
      const entityB = senders[j];
      const messagesA = messagesBySender.get(entityA) || [];
      const messagesB = messagesBySender.get(entityB) || [];
      const indicators = analyzeInteraction(messagesA, messagesB);
      if (indicators.length > 0) {
        await updateRelationship(runtime2, entityA, entityB, indicators);
      }
    }
  }
}
function analyzeInteraction(messagesA, messagesB) {
  const indicators = [];
  const friendPhrases = [
    /thanks.*friend/i,
    /you'?re a (great|good|true) friend/i,
    /appreciate you/i,
    /love you/i,
    /buddy|pal/i,
    /grab coffee/i
  ];
  const colleaguePhrases = [
    /code review/i,
    /project|meeting|deadline/i,
    /colleague|coworker/i,
    /work together/i,
    /team|department/i
  ];
  const communityPhrases = [
    /community|group/i,
    /event|meetup/i,
    /member/i,
    /contribute|volunteer/i,
    /help with|count me in/i,
    /together we can/i
  ];
  const allMessages = [...messagesA, ...messagesB];
  for (const msg of allMessages) {
    const text = msg.content?.text;
    if (!text)
      continue;
    for (const pattern of friendPhrases) {
      if (pattern.test(text)) {
        indicators.push({
          type: "friend",
          sentiment: determineSentiment(text),
          confidence: 0.8,
          context: text.substring(0, 100)
        });
      }
    }
    for (const pattern of colleaguePhrases) {
      if (pattern.test(text)) {
        indicators.push({
          type: "colleague",
          sentiment: determineSentiment(text),
          confidence: 0.7,
          context: text.substring(0, 100)
        });
      }
    }
    for (const pattern of communityPhrases) {
      if (pattern.test(text)) {
        indicators.push({
          type: "community",
          sentiment: determineSentiment(text),
          confidence: 0.6,
          context: text.substring(0, 100)
        });
      }
    }
  }
  return indicators;
}
function determineSentiment(text) {
  const positiveWords = [
    "thanks",
    "great",
    "good",
    "appreciate",
    "love",
    "helpful",
    "awesome"
  ];
  const negativeWords = [
    "harsh",
    "wrong",
    "bad",
    "terrible",
    "hate",
    "angry",
    "upset"
  ];
  const lowerText = text.toLowerCase();
  let positiveCount = 0;
  let negativeCount = 0;
  for (const word of positiveWords) {
    if (lowerText.includes(word))
      positiveCount++;
  }
  for (const word of negativeWords) {
    if (lowerText.includes(word))
      negativeCount++;
  }
  if (positiveCount > negativeCount)
    return "positive";
  if (negativeCount > positiveCount)
    return "negative";
  return "neutral";
}
async function updateRelationship(runtime2, entityA, entityB, indicators) {
  const relationships = await runtime2.getRelationships({
    entityIds: [entityA]
  });
  const relationship = relationships.find((r) => r.sourceEntityId === entityA && r.targetEntityId === entityB || r.sourceEntityId === entityB && r.targetEntityId === entityA);
  let primaryType = "acquaintance";
  let maxTypeCount = 0;
  const typeCounts = {};
  let positiveCount = 0;
  let negativeCount = 0;
  for (const indicator of indicators) {
    const nextCount = (typeCounts[indicator.type] ?? 0) + 1;
    typeCounts[indicator.type] = nextCount;
    if (nextCount > maxTypeCount) {
      maxTypeCount = nextCount;
      primaryType = indicator.type;
    }
    if (indicator.sentiment === "positive") {
      positiveCount += 1;
    } else if (indicator.sentiment === "negative") {
      negativeCount += 1;
    }
  }
  const halfCount = indicators.length / 2;
  const sentiment = positiveCount > halfCount ? "positive" : negativeCount > halfCount ? "negative" : "neutral";
  const serializeIndicators = (inds) => {
    return inds.map((ind) => ({
      type: ind.type,
      sentiment: ind.sentiment,
      confidence: ind.confidence,
      context: ind.context
    }));
  };
  if (!relationship) {
    await runtime2.createRelationship({
      sourceEntityId: entityA,
      targetEntityId: entityB,
      tags: ["rolodex", primaryType],
      metadata: {
        sentiment,
        indicators: serializeIndicators(indicators),
        autoDetected: true,
        strength: 0.5,
        relationshipType: primaryType,
        lastInteractionAt: new Date().toISOString()
      }
    });
  } else {
    const metadata = relationship.metadata || {};
    metadata.sentiment = sentiment;
    const existingIndicators = Array.isArray(metadata.indicators) ? metadata.indicators : [];
    const newIndicators = [
      ...existingIndicators,
      ...serializeIndicators(indicators)
    ];
    metadata.indicators = newIndicators;
    metadata.lastAnalyzed = Date.now();
    await runtime2.createRelationship({
      sourceEntityId: relationship.sourceEntityId,
      targetEntityId: relationship.targetEntityId,
      tags: [...relationship.tags || [], "updated"],
      metadata: {
        ...metadata,
        relationshipType: primaryType,
        lastInteractionAt: new Date().toISOString()
      }
    });
  }
}
function extractMentionedPeople(text) {
  const people = [];
  const patterns = [
    /(\w+ \w+) (?:is|was|works) (?:a|an|the|at|in) ([^.!?]+)/gi,
    /(?:met|know|talked to) (\w+ \w+)/gi,
    /(\w+)'s (birthday|email|phone|address) is ([^.!?]+)/gi
  ];
  for (const pattern of patterns) {
    let patternMatch = pattern.exec(text);
    while (patternMatch !== null) {
      if (patternMatch[1] && patternMatch[1].length > 3 && !patternMatch[1].match(/^(the|and|but|for|with)$/i)) {
        people.push({
          name: patternMatch[1],
          context: patternMatch[0],
          attributes: {}
        });
      }
      patternMatch = pattern.exec(text);
    }
  }
  return people;
}
async function createOrUpdateMentionedEntity(runtime2, person, mentionedBy) {
  let existing = null;
  const memories = await runtime2.getMemories({
    tableName: "entities",
    count: 1000,
    unique: true
  });
  for (const memory2 of memories) {
    if (memory2.entityId) {
      const entity = await runtime2.getEntityById(memory2.entityId);
      if (entity?.names.some((name) => name.toLowerCase() === person.name.toLowerCase())) {
        existing = entity;
        break;
      }
    }
  }
  if (!existing) {
    await runtime2.createEntity({
      id: stringToUuid(`mentioned-${person.name}-${Date.now()}`),
      agentId: runtime2.agentId,
      names: [person.name],
      metadata: {
        mentionedBy,
        mentionContext: person.context,
        attributes: person.attributes,
        createdFrom: "mention"
      }
    });
  } else {
    const metadata = existing.metadata || {};
    const mentions = metadata.mentions || [];
    mentions.push({
      by: mentionedBy,
      context: person.context,
      timestamp: Date.now()
    });
    metadata.mentions = mentions;
    await runtime2.updateEntity({ ...existing, metadata });
  }
}
async function assessTrustIndicators(runtime2, entityId, messages) {
  const userMessages = messages.filter((m) => m.entityId === entityId);
  if (userMessages.length === 0)
    return;
  const entity = await runtime2.getEntityById(entityId);
  if (!entity)
    return;
  const metadata = entity.metadata || {};
  const trustMetrics = metadata.trustMetrics || {
    helpfulness: 0,
    consistency: 0,
    engagement: 0,
    suspicionLevel: 0
  };
  let helpfulCount = 0;
  let suspiciousCount = 0;
  for (const msg of userMessages) {
    const text = msg.content?.text?.toLowerCase();
    if (!text)
      continue;
    if (text.match(/here'?s|let me help|i can help|try this|solution|answer/)) {
      helpfulCount++;
    }
    if (text.match(/delete all|give me access|send me your|password|private key|update my permissions|i'?m the new admin|give me.*details|send me.*keys/)) {
      suspiciousCount += 2;
    }
  }
  const totalMessages = userMessages.length || 1;
  trustMetrics.helpfulness = Math.min(1, trustMetrics.helpfulness * 0.8 + helpfulCount / totalMessages * 0.2);
  trustMetrics.suspicionLevel = Math.min(1, trustMetrics.suspicionLevel * 0.8 + suspiciousCount / totalMessages * 0.2);
  trustMetrics.engagement = userMessages.length;
  trustMetrics.lastAssessed = Date.now();
  metadata.trustMetrics = trustMetrics;
  await runtime2.updateEntity({ ...entity, metadata });
}
function detectPrivacyBoundaries(text) {
  const privacyPhrases = [
    /don'?t tell anyone/i,
    /keep.{0,20}confidential/i,
    /keep.{0,20}secret/i,
    /don'?t mention/i,
    /between you and me/i,
    /off the record/i,
    /private/i
  ];
  for (const pattern of privacyPhrases) {
    if (pattern.test(text)) {
      return {
        type: "confidential",
        content: text,
        context: "Privacy boundary detected"
      };
    }
  }
  return null;
}
async function handlePrivacyBoundary(runtime2, privacyInfo, message2) {
  const entity = await runtime2.getEntityById(message2.entityId);
  if (!entity)
    return;
  const metadata = entity.metadata || {};
  metadata.privateData = true;
  metadata.confidential = true;
  await runtime2.updateEntity({ ...entity, metadata });
  await runtime2.createComponent({
    id: stringToUuid(`privacy-${Date.now()}-${message2.entityId}`),
    type: "privacy_marker",
    agentId: runtime2.agentId,
    entityId: message2.entityId,
    roomId: message2.roomId,
    worldId: stringToUuid(`rolodex-world-${runtime2.agentId}`),
    sourceEntityId: message2.entityId,
    data: {
      privacyType: privacyInfo.type,
      privacyContent: privacyInfo.content,
      privacyContext: privacyInfo.context,
      timestamp: Date.now()
    },
    createdAt: Date.now()
  });
  logger.info({
    src: "plugin:advanced-capabilities:evaluator:relationship_extraction",
    agentId: runtime2.agentId,
    privacyInfo
  }, "Privacy boundary recorded");
}
async function handleAdminUpdates(runtime2, message2, _recentMessages) {
  const entity = await runtime2.getEntityById(message2.entityId);
  if (!entity || !entity.metadata?.isAdmin)
    return;
  const text = message2.content?.text;
  if (!text)
    return;
  const updatePattern = /(?:update|set|change)\s+(\w+(?:\s+\w+)*)'?s?\s+(\w+)\s+(?:to|is|=)\s+(.+)/i;
  const match = text.match(updatePattern);
  if (match) {
    const [, targetName, field, value] = match;
    const targetEntity = await findEntityByName2(runtime2, targetName, message2.roomId);
    if (targetEntity) {
      const metadata = targetEntity.metadata || {};
      metadata[field.toLowerCase()] = value;
      await runtime2.updateEntity({ ...targetEntity, metadata });
      logger.info({
        src: "plugin:advanced-capabilities:evaluator:relationship_extraction",
        agentId: runtime2.agentId,
        admin: message2.entityId,
        target: targetEntity.id,
        field,
        value
      }, "Admin updated entity metadata");
    }
  }
}
async function findEntityByName2(runtime2, name, roomId) {
  const entities = await runtime2.getEntitiesForRoom(roomId);
  for (const entity of entities) {
    if (entity.names.some((n2) => n2.toLowerCase() === name.toLowerCase())) {
      return entity;
    }
  }
  return null;
}
