var spec34 = requireProviderSpec("CONTACTS");
var contactsProvider = {
  name: spec34.name,
  description: spec34.description,
  get: async (runtime2, _message, _state2) => {
    const rolodexService = runtime2.getService("rolodex");
    if (!rolodexService) {
      runtime2.logger.warn("[ContactsProvider] RolodexService not available");
      return { text: "", values: {}, data: {} };
    }
    const contacts = await rolodexService.searchContacts({});
    if (contacts.length === 0) {
      return {
        text: "No contacts in rolodex.",
        values: { contactCount: 0 },
        data: {}
      };
    }
    const contactDetails = await Promise.all(contacts.map(async (contact) => {
      const entity = await runtime2.getEntityById(contact.entityId);
      return {
        id: contact.entityId,
        name: entity?.names[0] || "Unknown",
        categories: contact.categories,
        tags: contact.tags,
        preferences: contact.preferences,
        lastModified: contact.lastModified
      };
    }));
    const grouped = {};
    for (const contact of contactDetails) {
      for (const cat of contact.categories) {
        const bucket = grouped[cat];
        if (bucket) {
          bucket.push(contact);
        } else {
          grouped[cat] = [contact];
        }
      }
    }
    const lines = [];
    lines.push(`You have ${contacts.length} contacts in your rolodex:`);
    const categoryCounts = {};
    for (const category in grouped) {
      const items = grouped[category];
      if (!items)
        continue;
      categoryCounts[category] = items.length;
      lines.push("", `${category.charAt(0).toUpperCase() + category.slice(1)}s (${items.length}):`);
      for (const item of items) {
        let line = `- ${item.name}`;
        if (item.tags.length > 0) {
          line += ` [${item.tags.join(", ")}]`;
        }
        lines.push(line);
      }
    }
    const textSummary = lines.join(`
`).trim();
    return {
      text: textSummary,
      values: {
        contactCount: contacts.length,
        ...categoryCounts
      },
      data: categoryCounts
    };
  }
};
