var spec35 = requireProviderSpec("FACTS");
function formatFacts2(facts) {
  const result = [];
  for (let i = facts.length - 1;i >= 0; i -= 1) {
    result.push(facts[i]?.content.text ?? "");
  }
  return result.join(`
`);
}
var factsProvider = {
  name: spec35.name,
  description: spec35.description,
  dynamic: spec35.dynamic ?? true,
  get: async (runtime2, message2, _state2) => {
    const recentMessages = await runtime2.getMemories({
      tableName: "messages",
      roomId: message2.roomId,
      count: 10,
      unique: false
    });
    const lastMessageLines = [];
    for (let i = recentMessages.length - 1;i >= 0 && lastMessageLines.length < 5; i -= 1) {
      lastMessageLines.push(recentMessages[i]?.content.text ?? "");
    }
    lastMessageLines.reverse();
    const last5Messages = lastMessageLines.join(`
`);
    const embedding = await runtime2.useModel(ModelType.TEXT_EMBEDDING, {
      text: last5Messages
    });
    const [relevantFacts, recentFactsData] = await Promise.all([
      runtime2.searchMemories({
        tableName: "facts",
        embedding,
        roomId: message2.roomId,
        worldId: message2.worldId,
        count: 6,
        query: message2.content.text
      }),
      runtime2.searchMemories({
        embedding,
        query: message2.content.text,
        tableName: "facts",
        roomId: message2.roomId,
        entityId: message2.entityId,
        count: 6
      })
    ]);
    const seenIds = new Set;
    const allFacts = [];
    for (const fact of [...relevantFacts, ...recentFactsData]) {
      const factId = fact.id ?? "";
      if (factId && !seenIds.has(factId)) {
        seenIds.add(factId);
        allFacts.push(fact);
      }
    }
    if (allFacts.length === 0) {
      return {
        values: {
          facts: ""
        },
        data: {
          facts: allFacts
        },
        text: "No facts available."
      };
    }
    const formattedFacts = formatFacts2(allFacts);
    const agentName = runtime2.character.name ?? "Agent";
    const text = `Key facts that {{agentName}} knows:
{{formattedFacts}}`.replace("{{agentName}}", agentName).replace("{{formattedFacts}}", formattedFacts);
    return {
      values: {
        facts: formattedFacts
      },
      data: {
        facts: allFacts
      },
      text
    };
  }
};
