init_spec_helpers();
var spec36 = requireProviderSpec("FOLLOW_UPS");
var followUpsProvider = {
  name: spec36.name,
  description: spec36.description,
  get: async (runtime2, _message, _state2) => {
    const followUpService = runtime2.getService("follow_up");
    if (!followUpService) {
      runtime2.logger.warn("[FollowUpsProvider] FollowUpService not available");
      return { text: "", values: {}, data: {} };
    }
    const upcomingFollowUps = await followUpService.getUpcomingFollowUps(7, true);
    if (upcomingFollowUps.length === 0) {
      return {
        text: "No upcoming follow-ups scheduled.",
        values: { followUpCount: 0 },
        data: {}
      };
    }
    const now = Date.now();
    const contactIds = Array.from(new Set(upcomingFollowUps.map((f) => f.contact.entityId)));
    const entities = await Promise.all(contactIds.map((id) => runtime2.getEntityById(id)));
    const entityNames = new Map;
    for (let i = 0;i < contactIds.length; i += 1) {
      entityNames.set(contactIds[i], entities[i]?.names[0] || "Unknown");
    }
    const overdue = [];
    const upcoming = [];
    const scheduledAtMs = new Map;
    for (const item of upcomingFollowUps) {
      const scheduledAt = item.task.metadata?.scheduledAt ? new Date(item.task.metadata.scheduledAt).getTime() : 0;
      if (item.task.id) {
        scheduledAtMs.set(item.task.id, scheduledAt);
      }
      if (scheduledAt < now) {
        overdue.push(item);
      } else {
        upcoming.push(item);
      }
    }
    let textSummary = `You have ${upcomingFollowUps.length} follow-up${upcomingFollowUps.length !== 1 ? "s" : ""} scheduled:
`;
    if (overdue.length > 0) {
      textSummary += `
Overdue (${overdue.length}):
`;
      for (const f of overdue) {
        const name = entityNames.get(f.contact.entityId) || "Unknown";
        const scheduledAt = f.task.id ? scheduledAtMs.get(f.task.id) ?? 0 : 0;
        textSummary += `- ${name}`;
        if (scheduledAt > 0) {
          const daysOverdue = Math.floor((now - scheduledAt) / (1000 * 60 * 60 * 24));
          textSummary += ` (${daysOverdue} day${daysOverdue !== 1 ? "s" : ""} overdue)`;
        }
        if (f.task.metadata?.reason) {
          textSummary += ` - ${f.task.metadata.reason}`;
        }
        textSummary += `
`;
      }
    }
    if (upcoming.length > 0) {
      textSummary += `
Upcoming (${upcoming.length}):
`;
      for (const f of upcoming) {
        const name = entityNames.get(f.contact.entityId) || "Unknown";
        const scheduledAt = f.task.id ? scheduledAtMs.get(f.task.id) ?? 0 : 0;
        textSummary += `- ${name}`;
        if (scheduledAt > 0) {
          const daysUntil = Math.ceil((scheduledAt - now) / (1000 * 60 * 60 * 24));
          if (daysUntil === 0) {
            textSummary += " (today)";
          } else if (daysUntil === 1) {
            textSummary += " (tomorrow)";
          } else {
            textSummary += ` (in ${daysUntil} days)`;
          }
        }
        if (f.task.metadata?.reason) {
          textSummary += ` - ${f.task.metadata.reason}`;
        }
        textSummary += `
`;
      }
    }
    const suggestions = await followUpService.getFollowUpSuggestions();
    if (suggestions.length > 0) {
      textSummary += `
Suggested follow-ups:
`;
      suggestions.slice(0, 3).forEach((s) => {
        textSummary += `- ${s.entityName} (${s.daysSinceLastContact} days since last contact)
`;
      });
    }
    return {
      text: textSummary.trim(),
      values: {
        followUpCount: upcomingFollowUps.length,
        overdueCount: overdue.length,
        upcomingCount: upcoming.length,
        suggestionsCount: suggestions.length
      },
      data: {
        followUpCount: upcomingFollowUps.length,
        overdueCount: overdue.length,
        upcomingCount: upcoming.length,
        suggestionsCount: suggestions.length
      }
    };
  }
};
