var spec37 = requireProviderSpec("KNOWLEDGE");
var knowledgeProvider = {
  name: spec37.name,
  description: spec37.description,
  dynamic: spec37.dynamic ?? true,
  get: async (runtime2, message2, _state2) => {
    const queryText = message2.content?.text || "";
    if (!queryText) {
      return {
        text: "",
        values: {
          knowledgeCount: 0,
          hasKnowledge: false
        },
        data: {
          entries: [],
          query: ""
        }
      };
    }
    const embedding = await runtime2.useModel(ModelType.TEXT_EMBEDDING, {
      text: queryText
    });
    const relevantKnowledge = await runtime2.searchMemories({
      tableName: "knowledge",
      embedding,
      query: queryText,
      count: 5
    });
    if (relevantKnowledge.length === 0) {
      return {
        text: "",
        values: {
          knowledgeCount: 0,
          hasKnowledge: false
        },
        data: {
          entries: [],
          query: queryText
        }
      };
    }
    const sections = [];
    const knowledgeEntries = [];
    for (const entry of relevantKnowledge) {
      const text = entry.content?.text;
      if (!text)
        continue;
      let knowledgeText = text;
      if (knowledgeText.length > 500) {
        knowledgeText = `${knowledgeText.substring(0, 500)}...`;
      }
      knowledgeEntries.push({
        id: entry.id?.toString() || "",
        text: knowledgeText,
        source: entry.metadata?.source || "unknown"
      });
      sections.push(`- ${knowledgeText}`);
    }
    const contextText = sections.length > 0 ? `# Relevant Knowledge
${sections.join(`
`)}` : "";
    return {
      text: contextText,
      values: {
        knowledgeCount: knowledgeEntries.length,
        hasKnowledge: knowledgeEntries.length > 0
      },
      data: {
        entries: knowledgeEntries,
        query: queryText
      }
    };
  }
};
