var spec38 = requireProviderSpec("RELATIONSHIPS");
async function formatRelationships(runtime2, relationships) {
  const sortedRelationships = relationships.filter((rel) => rel.metadata?.interactions).sort((a, b) => (b.metadata && b.metadata.interactions || 0) - (a.metadata && a.metadata.interactions || 0)).slice(0, 30);
  if (sortedRelationships.length === 0) {
    return "";
  }
  const uniqueEntityIds = Array.from(new Set(sortedRelationships.map((rel) => rel.targetEntityId)));
  const entities = await Promise.all(uniqueEntityIds.map((id) => runtime2.getEntityById(id)));
  const entityMap = new Map;
  entities.forEach((entity, index) => {
    if (entity) {
      entityMap.set(uniqueEntityIds[index], entity);
    }
  });
  const formatMetadata = (metadata) => {
    if (!metadata)
      return "";
    const lines = [];
    for (const [key, value] of Object.entries(metadata)) {
      if (value && typeof value === "object") {
        lines.push(`${key}: ${JSON.stringify(value)}`);
      } else {
        lines.push(`${key}: ${String(value)}`);
      }
    }
    return lines.join(`
`);
  };
  const formattedRelationships = [];
  for (const rel of sortedRelationships) {
    const targetEntityId = rel.targetEntityId;
    const entity = entityMap.get(targetEntityId);
    if (!entity)
      continue;
    const names4 = entity.names.join(" aka ");
    const tags = rel.tags ? rel.tags.join(", ") : "";
    const metadata = formatMetadata(entity.metadata);
    const parts = [names4, tags, metadata].filter((part) => part.length > 0);
    formattedRelationships.push(`${parts.join(`
`)}
`);
  }
  return formattedRelationships.join(`
`);
}
var relationshipsProvider = {
  name: spec38.name,
  description: spec38.description,
  dynamic: spec38.dynamic ?? true,
  get: async (runtime2, message2) => {
    const relationships = await runtime2.getRelationships({
      entityIds: [message2.entityId]
    });
    if (!relationships || relationships.length === 0) {
      return {
        data: {
          relationships: []
        },
        values: {
          relationships: "No relationships found."
        },
        text: "No relationships found."
      };
    }
    const formattedRelationships = await formatRelationships(runtime2, relationships);
    if (!formattedRelationships) {
      return {
        data: {
          relationships: []
        },
        values: {
          relationships: "No relationships found."
        },
        text: "No relationships found."
      };
    }
    return {
      data: {
        relationships: formattedRelationships
      },
      values: {
        relationships: formattedRelationships
      },
      text: `# ${runtime2.character.name} has observed ${message2.content.senderName || message2.content.name} interacting with these people:
${formattedRelationships}`
    };
  }
};
