init_spec_helpers();
init_logger();
init_types5();
var spec39 = requireProviderSpec("ROLES");
var roleProvider = {
  name: spec39.name,
  description: spec39.description,
  get: async (runtime2, message2, state2) => {
    const room = state2.data.room ?? await runtime2.getRoom(message2.roomId);
    if (!room) {
      throw new Error("No room found");
    }
    if (room.type !== ChannelType.GROUP) {
      return {
        data: {
          roles: []
        },
        values: {
          roles: "No access to role information in DMs, the role provider is only available in group scenarios."
        },
        text: "No access to role information in DMs, the role provider is only available in group scenarios."
      };
    }
    const worldId = room.worldId;
    if (!worldId) {
      throw new Error("No world ID found for room");
    }
    logger.info({
      src: "plugin:advanced-capabilities:provider:roles",
      agentId: runtime2.agentId,
      worldId
    }, "Using world ID");
    const world = await runtime2.getWorld(worldId);
    if (!world || !world.metadata?.ownership?.ownerId) {
      logger.info({
        src: "plugin:advanced-capabilities:provider:roles",
        agentId: runtime2.agentId,
        worldId
      }, "No ownership data found for world, initializing empty role hierarchy");
      return {
        data: {
          roles: []
        },
        values: {
          roles: "No role information available for this server."
        },
        text: "No role information available for this server."
      };
    }
    const roles = world.metadata.roles || {};
    if (Object.keys(roles).length === 0) {
      logger.info({
        src: "plugin:advanced-capabilities:provider:roles",
        agentId: runtime2.agentId,
        worldId
      }, "No roles found for world");
      return {
        data: {
          roles: []
        },
        values: {
          roles: "No role information available for this server."
        },
        text: "No role information available for this server."
      };
    }
    logger.info({
      src: "plugin:advanced-capabilities:provider:roles",
      agentId: runtime2.agentId,
      roleCount: Object.keys(roles).length
    }, "Found roles");
    const owners = [];
    const admins = [];
    const members = [];
    const entityIds = Object.keys(roles);
    const entities = await Promise.all(entityIds.map((entityId) => runtime2.getEntityById(entityId)));
    const entityMap = new Map;
    for (let i = 0;i < entityIds.length; i += 1) {
      const entity = entities[i];
      if (entity) {
        entityMap.set(entityIds[i], entity);
      }
    }
    const seenUsernames = new Set;
    for (const entityId of entityIds) {
      const userRole = roles[entityId];
      const user = entityMap.get(entityId);
      const name = user?.metadata?.name;
      const username = user?.metadata?.username;
      const names4 = user?.names;
      if (!name || !username || !names4) {
        logger.warn({
          src: "plugin:advanced-capabilities:provider:roles",
          agentId: runtime2.agentId,
          entityId
        }, "User has no name or username, skipping");
        continue;
      }
      if (seenUsernames.has(username)) {
        continue;
      }
      seenUsernames.add(username);
      switch (userRole) {
        case "OWNER":
          owners.push({ name, username, names: names4 });
          break;
        case "ADMIN":
          admins.push({ name, username, names: names4 });
          break;
        default:
          members.push({ name, username, names: names4 });
          break;
      }
    }
    let response = `# Server Role Hierarchy

`;
    if (owners.length > 0) {
      response += `## Owners
`;
      owners.forEach((owner) => {
        response += `${owner.name} (${owner.names.join(", ")})
`;
      });
      response += `
`;
    }
    if (admins.length > 0) {
      response += `## Administrators
`;
      admins.forEach((admin) => {
        response += `${admin.name} (${admin.names.join(", ")}) (${admin.username})
`;
      });
      response += `
`;
    }
    if (members.length > 0) {
      response += `## Members
`;
      members.forEach((member) => {
        response += `${member.name} (${member.names.join(", ")}) (${member.username})
`;
      });
    }
    if (owners.length === 0 && admins.length === 0 && members.length === 0) {
      return {
        data: {
          roles: []
        },
        values: {
          roles: "No role information available for this server."
        },
        text: "No role information available for this server."
      };
    }
    return {
      data: {
        roles: response
      },
      values: {
        roles: response
      },
      text: response
    };
  }
};
