  const worlds = [...worldMap.values()].map((w) => ({
    ...w,
    agentId
  }));
  if (worlds.length)
    await adapter2.upsertWorlds(worlds);
  const rooms = [...roomMap.values()].map((r) => ({
    ...r,
    agentId
  }));
  if (rooms.length)
    await adapter2.upsertRooms(rooms);
