init_types5();

class ServiceBuilder {
  serviceType;
  startFn;
  stopFn;
  description;
  constructor(serviceType) {
    this.serviceType = serviceType;
    this.description = "";
  }
  withDescription(description) {
    this.description = description;
    return this;
  }
  withStart(startFn) {
    this.startFn = startFn;
    return this;
  }
  withStop(stopFn) {
    this.stopFn = stopFn;
    return this;
  }
  build() {
    const serviceType = this.serviceType;
    const description = this.description;
    const startFn = this.startFn;
    const stopFn = this.stopFn;
    const ServiceClassImpl = class extends Service {
      capabilityDescription = description;
      async stop() {
        if (stopFn) {
          await stopFn();
        }
      }
    };
    Object.defineProperty(ServiceClassImpl, "serviceType", {
      value: serviceType,
      writable: false,
      enumerable: true,
      configurable: false
    });
    const startMethod = async (runtime2) => {
      if (!startFn) {
        throw new Error(`Start function not defined for service ${serviceType}`);
      }
      return startFn(runtime2);
    };
    Object.defineProperty(ServiceClassImpl, "start", {
      value: startMethod,
      writable: false,
      enumerable: true,
      configurable: false
    });
    return ServiceClassImpl;
  }
}
function createService(serviceType) {
  return new ServiceBuilder(serviceType);
}
function defineService(definition) {
  return createService(definition.serviceType).withDescription(definition.description).withStart(definition.start).withStop(definition.stop || (() => Promise.resolve())).build();
}
